import azure.functions as func
from azure.storage.blob import BlobServiceClient, BlobClient
from azure.cosmos import CosmosClient
from azure.eventgrid import EventGridPublisherClient
import os

connection_string = os.getenv("AZURE_STORAGE_CONNECTION_STRING")
cosmos_endpoint = os.getenv("COSMOS_ENDPOINT")
cosmos_key = os.getenv("COSMOS_KEY")
eventgrid_key = os.getenv("EVENTGRID_KEY")

def main(req: func.HttpRequest) -> func.HttpResponse:
    blob_service_client = BlobServiceClient.from_connection_string(connection_string)
    cosmos_client = CosmosClient(cosmos_endpoint, cosmos_key)
    eventgrid_client = EventGridPublisherClient(eventgrid_key)

    # Process files from Blob Storage
    container_client = blob_service_client.get_container_client("mycontainer")
    for blob in container_client.list_blobs():
        blob_client = BlobClient.from_connection_string(connection_string, container_name="mycontainer", blob_name=blob.name)
        data = blob_client.download_blob().readall()

        # Do processing and write results to Cosmos DB
        container = cosmos_client.get_database_client("mydatabase").get_container_client("mycontainer")
        container.upsert_item(item={"id": blob.name, "data": data})

        # Send notifications via Event Grid
        eventgrid_client.send_event(
            event_type="MyCustomEventType",
            data={"message": "Processing complete for file: {}".format(blob.name)}
        )

    return func.HttpResponse("Processing complete", status_code=200)